import java.util.ArrayList;
import java.util.List;

public class Solution {
    public static long solve(long[] nums) {
        List<Integer> indices1 = new ArrayList<>();
        List<Integer> indices2 = new ArrayList<>();

        // Store indices of 1s and 2s
        for (int i = 0; i < nums.length; i++) {
            if (nums[i] == 1) {
                indices1.add(i);
            } else if (nums[i] == 2) {
                indices2.add(i);
            }
        }

        // Check if any valid pair exists
        if (indices1.isEmpty() || indices2.isEmpty()) {
            return -1;
        }

        long minDiff = Long.MAX_VALUE;

        // Iterate over all pairs (i, j) such that nums[i] == 1 and nums[j] == 2
        for (int i_idx : indices1) {
            for (int j_idx : indices2) {
                long diff = Math.abs(i_idx - j_idx);
                if (diff < minDiff) {
                    minDiff = diff;
                }
            }
        }

        return minDiff;
    }
}
