import java.util.ArrayList;
import java.util.List;
import java.util.Collections;

public class Solution {
    public static long solve(long[] nums) {
        List<Integer> indices1 = new ArrayList<>();
        List<Integer> indices2 = new ArrayList<>();

        for (int i = 0; i < nums.length; i++) {
            if (nums[i] == 1) {
                indices1.add(i);
            } else if (nums[i] == 2) {
                indices2.add(i);
            }
        }

        if (indices1.isEmpty() || indices2.isEmpty()) {
            return -1;
        }

        long minDiff = Long.MAX_VALUE;

        // Since both lists of indices are sorted (because we iterated through nums sequentially),
        // we can use a two-pointer approach to find the minimum absolute difference efficiently.
        int p1 = 0;
        int p2 = 0;

        while (p1 < indices1.size() && p2 < indices2.size()) {
            int i = indices1.get(p1);
            int j = indices2.get(p2);

            long currentDiff = Math.abs((long)i - j);
            minDiff = Math.min(minDiff, currentDiff);

            // Move the pointer associated with the smaller index,
            // as this is the only way to potentially reduce the difference.
            if (i < j) {
                p1++;
            } else if (j < i) {
                p2++;
            } else {
                // i == j, the difference is 0, which is the minimum possible.
                return 0;
            }
        }

        return minDiff;
    }
}
