import java.util.ArrayList;
import java.util.List;

class Solution {
    /**
     * Finds the minimum absolute difference between indices i and j such that nums[i] == 1 and nums[j] == 2.
     * 
     * @param nums The input array containing 0, 1, and 2.
     * @return The minimum absolute difference, or -1 if no such pair exists.
     */
    public static long solve(long[] nums) {
        List<Integer> onesIndices = new ArrayList<>();
        List<Integer> twosIndices = new ArrayList<>();

        // 1. Collect indices for 1s and 2s
        for (int i = 0; i < nums.length; i++) {
            if (nums[i] == 1) {
                onesIndices.add(i);
            } else if (nums[i] == 2) {
                twosIndices.add(i);
            }
        }

        // 2. Check if any valid pair exists
        if (onesIndices.isEmpty() || twosIndices.isEmpty()) {
            return -1;
        }

        // 3. Sort the index lists (although they are naturally sorted by the loop, this is safer/clearer if the input gathering changed)
        // Since we iterate sequentially, they are already sorted.

        // 4. Find the minimum absolute difference
        long minDiff = Long.MAX_VALUE;

        // A brute-force O(N1 * N2) approach where N1 and N2 are counts of 1s and 2s is acceptable given N <= 100.
        for (int i : onesIndices) {
            for (int j : twosIndices) {
                long diff = Math.abs((long)i - (long)j);
                if (diff < minDiff) {
                    minDiff = diff;
                }
            }
        }

        return minDiff;
    }
}
